&reftitle.returnvalues;

 &return.success;
 The operation also fails (returning &false;) if the CAS token does not
 match, i.e. the item was changed by another client since it was read.

  &reftitle.examples;



    Memcache::cas example


<?php
/* OO API */

$memcache_obj = new Memcache;
$memcache_obj->connect('memcache_host', 11211);

$memcache_obj->set('counter', 1);

/* read the item together with its CAS token */
$value = $memcache_obj->get('counter', $flags, $cas);

/* store the new value only if nobody changed the item in the meantime */
if ($memcache_obj->cas('counter', $value + 1, 0, 0, $cas)) {
    echo "Item updated\n";
} else {
    echo "Item was modified by someone else, retry\n";
}

?>




    memcache_cas example


<?php
/* procedural API */

$memcache_obj = memcache_connect('memcache_host', 11211);

memcache_set($memcache_obj, 'counter', 1);

/* fetch value and CAS token (passed by reference) */
$value = memcache_get($memcache_obj, 'counter', $flags, $cas);

/* conditional store */
memcache_cas($memcache_obj, 'counter', $value + 1, 0, 0, $cas);

?>
